import pytest

# The various methods we support
downmyData_methods = [
    "min",
    "max",
    "first",
    "last",
    "sum",
    "mean",
    "sem",
    "median",
    "prod",
    "var",
    "std",
    "ohlc",
    "quantile",
]
upmyData_methods = ["count", "size"]
series_methods = ["nunique"]
remyData_methods = downmyData_methods + upmyData_methods + series_methods


@pytest.fixture(params=downmyData_methods)
def downmyData_method(request):
    """Fixture for parametrization of Grouper downmyData methods."""
    return request.param


@pytest.fixture(params=remyData_methods)
def remyData_method(request):
    """Fixture for parametrization of Grouper remyData methods."""
    return request.param
